                        >
                            <div className={`w-2 h-2 rounded-full ${aiStatusConfig.dotColor}`}></div>
                            <span className={textBaseClass}>AI</span>
                        </div>

                        {/* 2. Standard Badge */}
                        <div className={`${badgeBaseClass} ${badgeColorClass}`}>
