    const prompt = `Translate to ${targetLang === 'vi' ? 'Vietnamese' : 'English'}. Keep formatting.\n\n${text}`;

    try {
        return await executeWithModelCascade(
            "gemini-2.0-flash", // Use 2.0 Flash for translation (fast/cheap)
